/**
 * End-to-End Integration Test: Full Flow
 *
 * Tests the complete user journey from registration through order placement:
 * 1. User Registration
 * 2. Login & Token Handling
 * 3. Organization Creation
 * 4. Menu Creation with Categories and Products
 * 5. Menu Publishing & QR Code Generation
 * 6. Order Placement
 * 7. Order Status Verification
 *
 * @module __tests__/e2e/full-flow.e2e.spec
 *
 * Prerequisites:
 * - PostgreSQL running with migrations applied
 * - Redis running
 * - Application running with `npm run dev`
 *
 * Run with:
 * ```bash
 * npm run test:e2e -- --testPathPattern=full-flow.e2e.spec.ts
 * ```
 */

import { describe, it, expect, beforeAll, afterAll } from 'vitest';
import supertest from 'supertest';

// Base URL for the API (can be configured via environment)
const BASE_URL = process.env.API_BASE_URL || 'http://localhost:3000';
const api = supertest(BASE_URL);

// Test data containers
interface TestContext {
  accessToken: string;
  refreshToken: string;
  userId: string;
  organizationId: string;
  menuId: string;
  categoryId: string;
  productId: string;
  tableId: string;
  orderId: string;
  orderNumber: string;
}

// Initialize test context
const ctx: TestContext = {
  accessToken: '',
  refreshToken: '',
  userId: '',
  organizationId: '',
  menuId: '',
  categoryId: '',
  productId: '',
  tableId: '',
  orderId: '',
  orderNumber: '',
};

// Generate unique test data
const testEmail = `e2e.test.${Date.now()}@example.com`;
const testPassword = 'SecureTestPass123!';
const testOrgName = `E2E Test Org ${Date.now()}`;

describe('E2E: Full Application Flow', () => {
  // ---------------------------------------------------------------------------
  // Phase 1: User Registration & Authentication
  // ---------------------------------------------------------------------------

  describe('Phase 1: Authentication Flow', () => {
    it('should register a new user', async () => {
      const response = await api
        .post('/api/v1/auth/register')
        .send({
          email: testEmail,
          password: testPassword,
          passwordConfirm: testPassword,
          firstName: 'E2E',
          lastName: 'TestUser',
          acceptTerms: true,
        })
        .expect(201);

      expect(response.body.success).toBe(true);
      expect(response.body.data).toBeDefined();
      expect(response.body.data.userId).toBeDefined();

      ctx.userId = response.body.data.userId;
    });

    it('should login with registered credentials', async () => {
      const response = await api
        .post('/api/v1/auth/login')
        .send({
          email: testEmail,
          password: testPassword,
          rememberMe: true,
        })
        .expect(200);

      expect(response.body.success).toBe(true);
      expect(response.body.data.tokens.accessToken).toBeDefined();
      expect(response.body.data.user).toBeDefined();

      ctx.accessToken = response.body.data.tokens.accessToken;
      ctx.userId = response.body.data.user.id;

      // Extract refresh token from cookies
      const cookies = response.headers['set-cookie'];
      if (cookies) {
        const refreshCookie = Array.isArray(cookies)
          ? cookies.find((c: string) => c.startsWith('refreshToken='))
          : cookies.startsWith('refreshToken=') ? cookies : undefined;
        if (refreshCookie) {
          const match = refreshCookie.match(/refreshToken=([^;]+)/);
          if (match) {
            ctx.refreshToken = match[1];
          }
        }
      }
    });

    it('should get current user profile', async () => {
      const response = await api
        .get('/api/v1/auth/me')
        .set('Authorization', `Bearer ${ctx.accessToken}`)
        .expect(200);

      expect(response.body.success).toBe(true);
      expect(response.body.data.email).toBe(testEmail);
    });

    it('should refresh access token', async () => {
      if (!ctx.refreshToken) {
        console.warn('Skipping refresh test - no refresh token available');
        return;
      }

      const response = await api
        .post('/api/v1/auth/refresh')
        .set('Cookie', `refreshToken=${ctx.refreshToken}`)
        .expect(200);

      expect(response.body.success).toBe(true);
      expect(response.body.data.tokens.accessToken).toBeDefined();

      // Update access token
      ctx.accessToken = response.body.data.tokens.accessToken;
    });
  });

  // ---------------------------------------------------------------------------
  // Phase 2: Organization Creation
  // ---------------------------------------------------------------------------

  describe('Phase 2: Organization Creation', () => {
    it('should create a new organization', async () => {
      const response = await api
        .post('/api/v1/organizations')
        .set('Authorization', `Bearer ${ctx.accessToken}`)
        .send({
          name: testOrgName,
          email: `org.${testEmail}`,
          phone: '+90 555 123 4567',
          address: 'Test Street, Istanbul',
          description: 'E2E Test Organization',
        })
        .expect(201);

      expect(response.body.success).toBe(true);
      expect(response.body.data.organization).toBeDefined();
      expect(response.body.data.organization.name).toBe(testOrgName);

      ctx.organizationId = response.body.data.organization.id;
    });

    it('should get organization details', async () => {
      const response = await api
        .get(`/api/v1/organizations/${ctx.organizationId}`)
        .set('Authorization', `Bearer ${ctx.accessToken}`)
        .expect(200);

      expect(response.body.success).toBe(true);
      expect(response.body.data.id).toBe(ctx.organizationId);
    });
  });

  // ---------------------------------------------------------------------------
  // Phase 3: Menu Creation
  // ---------------------------------------------------------------------------

  describe('Phase 3: Menu Creation', () => {
    it('should create a new menu', async () => {
      const response = await api
        .post('/api/v1/menus')
        .set('Authorization', `Bearer ${ctx.accessToken}`)
        .set('X-Organization-Id', ctx.organizationId)
        .send({
          name: 'E2E Test Menu',
          description: 'A menu created for E2E testing',
          settings: {
            showPrices: true,
            enableOrdering: true,
            showAllergens: true,
          },
        })
        .expect(201);

      expect(response.body.success).toBe(true);
      expect(response.body.data.menu).toBeDefined();
      expect(response.body.data.menu.name).toBe('E2E Test Menu');

      ctx.menuId = response.body.data.menu.id;
    });

    it('should create a category in the menu', async () => {
      const response = await api
        .post('/api/v1/categories')
        .set('Authorization', `Bearer ${ctx.accessToken}`)
        .set('X-Organization-Id', ctx.organizationId)
        .send({
          menuId: ctx.menuId,
          name: 'E2E Test Category',
          description: 'A category for testing',
        })
        .expect(201);

      expect(response.body.success).toBe(true);
      expect(response.body.data.category).toBeDefined();

      ctx.categoryId = response.body.data.category.id;
    });

    it('should create a product in the category', async () => {
      const response = await api
        .post('/api/v1/products')
        .set('Authorization', `Bearer ${ctx.accessToken}`)
        .set('X-Organization-Id', ctx.organizationId)
        .send({
          categoryId: ctx.categoryId,
          name: 'E2E Test Burger',
          description: 'A delicious test burger',
          basePrice: 150.00,
          isActive: true,
          isAvailable: true,
          variants: [
            { name: 'Regular', price: 150.00, isActive: true },
            { name: 'Large', price: 200.00, isActive: true },
          ],
          modifiers: [
            { name: 'Extra Cheese', price: 20.00, isActive: true },
            { name: 'Bacon', price: 30.00, isActive: true },
          ],
        })
        .expect(201);

      expect(response.body.success).toBe(true);
      expect(response.body.data.product).toBeDefined();
      expect(response.body.data.product.name).toBe('E2E Test Burger');

      ctx.productId = response.body.data.product.id;
    });

    it('should get menu with full relations', async () => {
      const response = await api
        .get(`/api/v1/menus/${ctx.menuId}`)
        .set('Authorization', `Bearer ${ctx.accessToken}`)
        .set('X-Organization-Id', ctx.organizationId)
        .expect(200);

      expect(response.body.success).toBe(true);
      expect(response.body.data.id).toBe(ctx.menuId);
      expect(response.body.data.categories).toBeDefined();
      expect(response.body.data.categories.length).toBeGreaterThan(0);
    });
  });

  // ---------------------------------------------------------------------------
  // Phase 4: Menu Publishing & QR Code
  // ---------------------------------------------------------------------------

  describe('Phase 4: Menu Publishing', () => {
    it('should publish the menu with QR code generation', async () => {
      const response = await api
        .post(`/api/v1/menus/${ctx.menuId}/publish`)
        .set('Authorization', `Bearer ${ctx.accessToken}`)
        .set('X-Organization-Id', ctx.organizationId)
        .send({
          generateQrCode: true,
        })
        .expect(200);

      expect(response.body.success).toBe(true);
      expect(response.body.data.menu.isPublished).toBe(true);
      // QR code URL may be included if QR code generation is implemented
      // expect(response.body.data.qrCodeUrl).toBeDefined();
    });

    it('should verify menu is published', async () => {
      const response = await api
        .get(`/api/v1/menus/${ctx.menuId}`)
        .set('Authorization', `Bearer ${ctx.accessToken}`)
        .set('X-Organization-Id', ctx.organizationId)
        .expect(200);

      expect(response.body.success).toBe(true);
      expect(response.body.data.isPublished).toBe(true);
    });
  });

  // ---------------------------------------------------------------------------
  // Phase 5: Table & Order Setup
  // ---------------------------------------------------------------------------

  describe('Phase 5: Table & Order Setup', () => {
    it('should create a table for orders', async () => {
      // Note: Table creation might be part of the order module
      // This test assumes there's a tables endpoint
      const response = await api
        .post('/api/v1/tables')
        .set('Authorization', `Bearer ${ctx.accessToken}`)
        .set('X-Organization-Id', ctx.organizationId)
        .send({
          number: 'T01',
          capacity: 4,
          status: 'AVAILABLE',
        });

      // If table creation succeeds, store the ID
      if (response.status === 201) {
        expect(response.body.success).toBe(true);
        ctx.tableId = response.body.data.table?.id || response.body.data.id;
      } else {
        // Table endpoint might not exist or require different approach
        console.warn('Table creation skipped - endpoint may not be available');
      }
    });
  });

  // ---------------------------------------------------------------------------
  // Phase 6: Order Placement
  // ---------------------------------------------------------------------------

  describe('Phase 6: Order Placement', () => {
    it('should create an order', async () => {
      const orderData: Record<string, unknown> = {
        type: 'DINE_IN',
        items: [
          {
            productId: ctx.productId,
            quantity: 2,
            notes: 'No onions please',
          },
        ],
        notes: 'E2E Test Order',
      };

      // Add table ID if available
      if (ctx.tableId) {
        orderData.tableId = ctx.tableId;
      }

      const response = await api
        .post('/api/v1/orders')
        .set('Authorization', `Bearer ${ctx.accessToken}`)
        .set('X-Organization-Id', ctx.organizationId)
        .send(orderData)
        .expect(201);

      expect(response.body.success).toBe(true);
      expect(response.body.data.order).toBeDefined();
      expect(response.body.data.order.status).toBe('PENDING');

      ctx.orderId = response.body.data.order.id;
      ctx.orderNumber = response.body.data.order.orderNumber;
    });

    it('should get order details', async () => {
      const response = await api
        .get(`/api/v1/orders/${ctx.orderId}`)
        .set('Authorization', `Bearer ${ctx.accessToken}`)
        .set('X-Organization-Id', ctx.organizationId)
        .expect(200);

      expect(response.body.success).toBe(true);
      expect(response.body.data.id).toBe(ctx.orderId);
      expect(response.body.data.items).toBeDefined();
      expect(response.body.data.items.length).toBeGreaterThan(0);
    });

    it('should get order by order number', async () => {
      const response = await api
        .get(`/api/v1/orders/number/${ctx.orderNumber}`)
        .set('Authorization', `Bearer ${ctx.accessToken}`)
        .set('X-Organization-Id', ctx.organizationId)
        .expect(200);

      expect(response.body.success).toBe(true);
      expect(response.body.data.orderNumber).toBe(ctx.orderNumber);
    });
  });

  // ---------------------------------------------------------------------------
  // Phase 7: Order Status Workflow
  // ---------------------------------------------------------------------------

  describe('Phase 7: Order Status Workflow', () => {
    it('should confirm the order', async () => {
      const response = await api
        .post(`/api/v1/orders/${ctx.orderId}/confirm`)
        .set('Authorization', `Bearer ${ctx.accessToken}`)
        .set('X-Organization-Id', ctx.organizationId)
        .expect(200);

      expect(response.body.success).toBe(true);
      expect(response.body.data.order.status).toBe('CONFIRMED');
      expect(response.body.data.previousStatus).toBe('PENDING');
    });

    it('should start preparing the order', async () => {
      const response = await api
        .post(`/api/v1/orders/${ctx.orderId}/prepare`)
        .set('Authorization', `Bearer ${ctx.accessToken}`)
        .set('X-Organization-Id', ctx.organizationId)
        .expect(200);

      expect(response.body.success).toBe(true);
      expect(response.body.data.order.status).toBe('PREPARING');
    });

    it('should mark the order as ready', async () => {
      const response = await api
        .post(`/api/v1/orders/${ctx.orderId}/ready`)
        .set('Authorization', `Bearer ${ctx.accessToken}`)
        .set('X-Organization-Id', ctx.organizationId)
        .expect(200);

      expect(response.body.success).toBe(true);
      expect(response.body.data.order.status).toBe('READY');
    });

    it('should appear in kitchen orders', async () => {
      const response = await api
        .get('/api/v1/orders/kitchen')
        .set('Authorization', `Bearer ${ctx.accessToken}`)
        .set('X-Organization-Id', ctx.organizationId)
        .expect(200);

      expect(response.body.success).toBe(true);
      // Kitchen orders should include our test order or recently completed orders
    });

    it('should mark the order as delivered', async () => {
      const response = await api
        .post(`/api/v1/orders/${ctx.orderId}/deliver`)
        .set('Authorization', `Bearer ${ctx.accessToken}`)
        .set('X-Organization-Id', ctx.organizationId)
        .expect(200);

      expect(response.body.success).toBe(true);
      expect(response.body.data.order.status).toBe('DELIVERED');
    });

    it('should complete the order', async () => {
      const response = await api
        .post(`/api/v1/orders/${ctx.orderId}/complete`)
        .set('Authorization', `Bearer ${ctx.accessToken}`)
        .set('X-Organization-Id', ctx.organizationId)
        .expect(200);

      expect(response.body.success).toBe(true);
      expect(response.body.data.order.status).toBe('COMPLETED');
    });
  });

  // ---------------------------------------------------------------------------
  // Phase 8: Verification & Admin View
  // ---------------------------------------------------------------------------

  describe('Phase 8: Final Verification', () => {
    it('should list all orders including completed one', async () => {
      const response = await api
        .get('/api/v1/orders')
        .set('Authorization', `Bearer ${ctx.accessToken}`)
        .set('X-Organization-Id', ctx.organizationId)
        .query({ page: 1, perPage: 10 })
        .expect(200);

      expect(response.body.success).toBe(true);
      expect(response.body.data).toBeDefined();
      expect(Array.isArray(response.body.data)).toBe(true);

      // Find our completed order
      const completedOrder = response.body.data.find(
        (order: { id: string }) => order.id === ctx.orderId
      );
      expect(completedOrder).toBeDefined();
      expect(completedOrder.status).toBe('COMPLETED');
    });

    it('should get order statistics', async () => {
      const response = await api
        .get('/api/v1/orders/statistics')
        .set('Authorization', `Bearer ${ctx.accessToken}`)
        .set('X-Organization-Id', ctx.organizationId)
        .expect(200);

      expect(response.body.success).toBe(true);
      expect(response.body.data).toBeDefined();
      // Statistics should include counts, totals, etc.
      expect(typeof response.body.data.totalOrders).toBe('number');
    });

    it('should verify menu with products still accessible', async () => {
      const response = await api
        .get(`/api/v1/menus/${ctx.menuId}`)
        .set('Authorization', `Bearer ${ctx.accessToken}`)
        .set('X-Organization-Id', ctx.organizationId)
        .expect(200);

      expect(response.body.success).toBe(true);
      expect(response.body.data.isPublished).toBe(true);
    });
  });

  // ---------------------------------------------------------------------------
  // Cleanup & Logout
  // ---------------------------------------------------------------------------

  describe('Cleanup', () => {
    it('should logout successfully', async () => {
      const response = await api
        .post('/api/v1/auth/logout')
        .set('Authorization', `Bearer ${ctx.accessToken}`)
        .send({})
        .expect(204);

      // No content expected on success
    });
  });
});

// ---------------------------------------------------------------------------
// Test Summary Report
// ---------------------------------------------------------------------------

describe('Test Summary', () => {
  it('should output test context for debugging', () => {
    console.log('\n========================================');
    console.log('E2E Test Summary');
    console.log('========================================');
    console.log(`Test Email: ${testEmail}`);
    console.log(`Organization: ${testOrgName}`);
    console.log(`User ID: ${ctx.userId}`);
    console.log(`Organization ID: ${ctx.organizationId}`);
    console.log(`Menu ID: ${ctx.menuId}`);
    console.log(`Category ID: ${ctx.categoryId}`);
    console.log(`Product ID: ${ctx.productId}`);
    console.log(`Table ID: ${ctx.tableId || 'N/A'}`);
    console.log(`Order ID: ${ctx.orderId}`);
    console.log(`Order Number: ${ctx.orderNumber}`);
    console.log('========================================\n');

    // This test always passes - it's for logging
    expect(true).toBe(true);
  });
});
